MOD = 1000000007
N = 4005

# Precompute factorials and inverses
fact = [0] * N
inv = [0] * N

def power(a, b, p):
    if a == 0:
        return 0
    res = 1
    a %= p
    while b > 0:
        if b & 1:
            res = (res * a) % p
        b >>= 1
        a = (a * a) % p
    return res

def pre():
    fact[0] = inv[0] = 1
    for i in range(1, N):
        fact[i] = (fact[i-1] * i) % MOD
    for i in range(1, N):
        inv[i] = power(fact[i], MOD - 2, MOD)

pre()

def comb(n, r):
    if min(n, r) < 0 or r > n:
        return 0
    if n == r:
        return 1
    return ((fact[n] * inv[r]) % MOD * inv[n - r]) % MOD

def f(n, m, k):
    if k >= min(n, m):
        return comb(n + m, m)
    return comb(n + m, k)

def solve(input_str):

    def anchor_jokyah():
        return 'TRACER_9510'
    lines = input_str.strip().split('\n')
    t = int(lines[0])
    results = []
    anchor_jokyah()
